import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Accept Rows (Apply an Import)","description":"","frontmatter":{},"headers":[],"relativePath":"imports/apply-import.md","filePath":"imports/apply-import.md"}'),l={name:"imports/apply-import.md"};function i(n,e,s,p,c,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="accept-rows-apply-an-import" tabindex="-1">Accept Rows (Apply an Import) <a class="header-anchor" href="#accept-rows-apply-an-import" aria-label="Permalink to &quot;Accept Rows (Apply an Import)&quot;">​</a></h1><p>Accepting is the moment an import stops being review-only and starts writing real data.</p><blockquote><p>Screenshot placeholder: import-conflict.png Screenshot placeholder: import-accept-all.png</p></blockquote><h2 id="what-accept-does" tabindex="-1">What accept does <a class="header-anchor" href="#what-accept-does" aria-label="Permalink to &quot;What accept does&quot;">​</a></h2><p>When you accept a row, the app can:</p><ul><li>save it against a matched player</li><li>create a new player and then save it</li><li>overwrite an existing result, if the row is a conflict and you approve it</li></ul><p>That is why accept is the real &quot;apply&quot; step.</p><h2 id="created-vs-matched" tabindex="-1">Created vs matched <a class="header-anchor" href="#created-vs-matched" aria-label="Permalink to &quot;Created vs matched&quot;">​</a></h2><ul><li><strong>Matched</strong> means the row linked to a player already in the tracker.</li><li><strong>Created</strong> means the row created a brand-new player during accept.</li></ul><p>That difference appears again in the row status after save.</p><h2 id="conflict-rows" tabindex="-1">Conflict rows <a class="header-anchor" href="#conflict-rows" aria-label="Permalink to &quot;Conflict rows&quot;">​</a></h2><p>If a row is marked <strong>conflict</strong>, a result already exists for that player and event context.</p><p>Accepting the row means:</p><ul><li>you are choosing to overwrite the existing saved result</li><li>the import change trail records that overwrite</li></ul><p>Do not accept conflict rows blindly.</p><h2 id="power-and-role-safety-guards" tabindex="-1">Power and role safety guards <a class="header-anchor" href="#power-and-role-safety-guards" aria-label="Permalink to &quot;Power and role safety guards&quot;">​</a></h2><p>For alliance-player style imports, the tracker uses safety rules when applying updates:</p><ul><li>a valid existing power is not replaced by an invalid or missing OCR power</li><li>role, rank, and membership-style updates only apply when the player belongs in the same alliance context</li><li>if the player is currently in a different alliance, the import can still update usable power data, but it does not hijack membership into the wrong alliance</li></ul><h2 id="accept-one-vs-accept-all" tabindex="-1">Accept one vs accept all <a class="header-anchor" href="#accept-one-vs-accept-all" aria-label="Permalink to &quot;Accept one vs accept all&quot;">​</a></h2><ul><li>use <strong>Accept</strong> when only one row is ready</li><li>use <strong>Accept all</strong> when you trust the remaining attention rows enough to save them in one sweep</li></ul><p>If some rows fail, the page reports how many were accepted and how many still need manual work.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./review-rows.html">Review Import Rows</a></li><li><a href="./import-mistakes.html">Fixing Import Mistakes</a></li><li><a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a></li></ul>',23)])])}const u=a(l,[["render",i]]);export{m as __pageData,u as default};
